class AuthGuard {
    constructor(prior, router, authService, appStorage, roleService, toastService, menuService) {
        this.router = router;
        this.authService = authService;
        this.appStorage = appStorage;
        this.roleService = roleService;
        this.toastService = toastService;
        this.menuService = menuService;
        this.deniedMessage = 'Unauthorized Access Denied';
        if (prior) {
            return prior;
        }
    }
    /**
     * @description canActivate
     * @param next next
     * @param state state
     */
    canActivate(next, state) {
        if (this.authService.isLoggedIn()) {
            let privacy;
            let userType = '';
            privacy = this.appStorage.get('privacy');
            if (privacy === 'Kreedo Super Admin') {
                userType = 'kreedoSuperAdmin';
            }
            else if (privacy === 'Kreedo Site Admin') {
                userType = 'kreedoSiteAdmin';
            }
            else if (privacy === 'Delivery Head') {
                userType = 'deliveryHead';
            }
            else if (privacy === 'Account Manager') {
                userType = 'accountManager';
            }
            else if (privacy === 'Senior Learning Manager') {
                userType = 'seniorLearningManager';
            }
            else if (privacy === 'Learning Manager') {
                userType = 'learningManager';
            }
            else if (privacy === 'School Account Owner') {
                userType = 'schoolAccountOwner';
            }
            else if (privacy === 'School Admin') {
                userType = 'schoolAdmin';
            }
            else if (privacy === 'School Associate') {
                userType = 'schoolAssociate';
            }
            else if (privacy === 'Class Teacher') {
                userType = 'classTeacher';
            }
            else if (privacy === 'Subject Teacher') {
                userType = 'subjectTeacher';
            }
            else if (privacy === 'Assessment Teacher') {
                userType = 'assessmentTeacher';
            }
            else if (privacy === 'Internal User') {
                userType = 'InternalUser';
            }
            else {
                userType = '';
            }
            if (userType) {
                let hasRoutePermission = this.roleService.hasRoutePermission(userType, state.url);
                if (!hasRoutePermission) {
                    this.toastService.activateSuccess(this.deniedMessage);
                    this.router.navigate(['/']);
                    return false;
                }
                else {
                    if (next.data['name'] && next.data['name'] === 'auth') {
                        this.router.navigate(['/']);
                        return false;
                    }
                    else {
                        return hasRoutePermission;
                    }
                }
            }
            else {
                this.menuService.dynamicMenus.next([]);
                this.authService.logout();
                return false;
            }
        }
        else {
            if (next.data['name'] && next.data['name'] === 'auth') {
                return true;
            }
            else {
                this.router.navigate(['/auth']);
                return false;
            }
        }
    }
}
