class TARoleComponent {
    constructor(router, appStorageService, apiService, titleService, authService, loadingService, pageHeaderService) {
        this.router = router;
        this.appStorageService = appStorageService;
        this.apiService = apiService;
        this.titleService = titleService;
        this.authService = authService;
        this.loadingService = loadingService;
        this.pageHeaderService = pageHeaderService;
        this.sections = '';
        this.selectedGrade = '';
        this.selectedSection = '';
        this.schoolId = '';
    }
    ngOnInit() {
        this.titleService.setTitle('Kreedo Admin | TM - Form');
        this.pageHeaderService.setPageHeader('TM - Form');
        this.schoolId = this.appStorageService.get('schoolId');
        this.getDraftQuestions();
        this.getTaGradeSectionList();
    }
    Test() {
        this.router.navigate(['management/taform/Ta-Form']);
    }
    onGradeChange(gradeId) {
        const grade = this.grades.find((g) => g.grade_id === gradeId);
        if (grade && grade.sections) {
            this.sections = grade.sections;
            localStorage.setItem("selectedGrade", JSON.stringify({
                grade_id: grade.grade_id,
                grade_label: grade.grade_name
            }));
        }
        else {
            this.sections = [];
            localStorage.removeItem("selectedGrade");
        }
    }
    onSectionChange(sectionId) {
        const section = this.sections.find((s) => s.section_id === sectionId);
        if (section) {
            localStorage.setItem("selectedSection", JSON.stringify({
                section_id: section.section_id,
                section_name: section.section_name
            }));
        }
    }
    getDraftQuestions() {
        let param = {
            queryParams: {
                // id: this.schoolId
                school_id: this.schoolId,
                is_draft: true
            }
        };
        this.loadingService.show();
        this.apiService.request("TAAPPROVESTATUSLIST", param).subscribe((response) => {
            if (response.isSuccess) {
                this.draftForms = response.data.results;
            }
            this.loadingService.hide();
        }, error => {
            this.loadingService.hide();
        });
    }
    getTaGradeSectionList() {
        let param = {
            queryParams: {
                school_id: this.schoolId
            }
        };
        this.loadingService.show();
        this.apiService.request("TAGRADESECTIONLIST", param).subscribe((response) => {
            if (response.isSuccess) {
                let data = response.data;
                this.grades = data;
            }
            this.loadingService.hide();
        }, error => {
            this.loadingService.hide();
        });
    }
    RedirectToTAForm(id) {
        this.router.navigate(['/management/taform/Ta-Form/', id]);
    }
}
